function StructInvasionMap:StructInvasionMap()

end

function StructInvasionMap:CreateByPb(pb)
    self.refId = pb.refId
    local event = nil
    local eventList
    local eventMap
    if pb.syncType == 0 then
        self.eventInfo = {}
        self.eventMap = {}
        eventList = self.eventInfo
        eventMap = self.eventMap
    else
        eventList = self.eventInfo or {}
        self.eventInfo = eventList

        eventMap = self.eventMap or {}
        self.eventMap = eventMap
    end

    local key = nil
    local powerList = nil
    local isNew = nil
    for k,v in ipairs(pb.eventInfo) do

        powerList = {}
        for k1,v1 in ipairs(v.monsterPower) do
            table.insert(powerList,v1)
        end
        isNew = false
        key = string.format("%s|%s",v.x,v.y)
        event = eventMap[key]
        if not event then
            isNew = true
            event = {}
            eventMap[key] = event
        end
        event.eventGroupRefId = v.eventGroupRefId
        event.randomEventRefId = v.randomEventRefId
        event.x = v.x
        event.y = v.y
        event.state = v.state
        event.monsterPower = powerList
        event.refreshCount = v.refreshCount

        if isNew then
            table.insert(eventList,event)
        end
    end

    self._monsterList = nil
    self._boxEventList = nil
end

function StructInvasionMap:GetEventByPos(x,y)
    local key = string.format("%s|%s",x,y)

    return self.eventMap[key]
end

function StructInvasionMap:SetEventInfo(eventInfo)
    local key = string.format("%s|%s",eventInfo.x,eventInfo.y)
    local event = self.eventMap[key]
    if event then
        event.state = eventInfo.state
        local powerList = {}
        for k1,v1 in ipairs(eventInfo.monsterPower) do
            table.insert(powerList,v1)
        end
        event.monsterPower = powerList
    end
end

function StructInvasionMap:GetMonsterEventList(type)
    if self._monsterList then
        return self._monsterList[type]
    end
    local monsterList = {}
    local refId
    local ref
    local eventType
    local isBoxEvent
    for k,v in ipairs(self.eventInfo) do
        if v.state ==0 then
            refId     = v.randomEventRefId
            --ref       = gModelInvasion:GetEventRef(refId)
            eventType = ref.type
            --isBoxEvent = gModelInvasion:IsBoxEventType(eventType)
            if not isBoxEvent then
                local list = monsterList[eventType]
                if not list then
                    list = {}
                    monsterList[eventType] = list
                end
                table.insert(list,v)
            end

        end
    end


    self._monsterList = monsterList

    return monsterList[type]
end

function StructInvasionMap:GetBoxEventList()

    if self._boxEventList then
        return self._boxEventList
    end
    local refId
    local ref
    local eventType
    local isBoxEvent

    local boxList = {}
    for k,v in ipairs(self.eventInfo) do
        if v.state ==0 then
            refId     = v.randomEventRefId
            ref       = gModelInvasion:GetEventRef(refId)
            eventType = ref.type
            isBoxEvent = gModelInvasion:IsBoxEventType(eventType)

            if isBoxEvent then
                local data = {
                    sort = eventType,
                    eventData = v,
                }
                table.insert(boxList,data)
            end
        end
    end

    table.sort(boxList,function (a,b)

        return a.sort > b.sort
    end)

    self._boxEventList = boxList
    return boxList
end




return StructInvasionMap